  ('social-worker-moex-00441', 'social-worker', 'social-worker-moex-113-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某縣市政府委託的「兒少保護親職教育輔導方案」，規劃明年度服務，需達到每季訪視輔導150人 次、電話訪視300人次、資源聯結150人次、課程辦理20場次、諮商時數80小時，係屬於以下 何種服務績效？', '["輸入（input）", "過程（throughput）", "輸出（output）", "成果（outcome）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "890a7ba83f8f", "answer_pdf_sha1": "96773571a3bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00442', 'social-worker', 'social-worker-moex-113-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列有關方案「邏輯模型（logicmodel）」中四項重要內容的敘述，何者錯誤？', '["方案運用的資源", "方案未來的發展與機會", "方案運用的程序與計畫的活動", "方案預期的產出或輸出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "890a7ba83f8f", "answer_pdf_sha1": "96773571a3bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00443', 'social-worker', 'social-worker-moex-113-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會服務組織變革的敘述，下列何者錯誤？', '["將服務使用者納入服務規劃和輸送的新方式，因此需要變革", "技術創新不屬於組織變革的因素", "政府政策與規範的改變，影響社會服務組織的運作，因此需要變革", "政治環境的變化也是造成組織變革的因素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "890a7ba83f8f", "answer_pdf_sha1": "96773571a3bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00444', 'social-worker', 'social-worker-moex-113-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案執行過程中，「輸出」指的是方案活動的直接產物，目的是要確認服務對象實際接受的服務 量以及是否接受所有的服務。下列有關輸出的敘述，何者正確？', '["在一個為期一年的服務方案中，計算「每位社工在每個星期與服務對象接觸的時間與服務類型 次數」，此為「最終輸出」", "為能清楚計算「中間輸出」，需先界定服務單位", "「甲機構計算其自開始服務以來，每月可提供予服務對象60人次的個別諮商服務」，此為採用 時間單位", "以一個「協助孕婦到醫院完成至少6次之產前檢查的產前照護方案」為例，若計算的重點在於 「共有多少服務對象接受完整服務」，此為「中間輸出」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "890a7ba83f8f", "answer_pdf_sha1": "96773571a3bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00445', 'social-worker', 'social-worker-moex-113-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關「人力資源管理（HRM）」之敘述，下列何者錯誤？', '["確信有合乎組織各目標之可用員工的正式過程，係屬晉用（staffing）", "著重提供適宜的工作條件或環境，以增進員工對組織的認同，係屬維持（maintenance）", "協助員工習得新技能、改善技能，係屬領導（leadership）", "促使員工努力追求組織目標的意願，係屬激勵（motivation）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "890a7ba83f8f", "answer_pdf_sha1": "96773571a3bf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
